package agent

import (
	"encoding/json"
	"os"
	"path/filepath"
	"time"
)

const (
	routingOutcomeFileName = "routing-outcomes.jsonl"
	burnSummaryFileName    = "burn-summaries.jsonl"
)

// RoutingMetricsStore persists minimal routing outcome and quota snapshot data.
type RoutingMetricsStore struct {
	Dir string
}

// NewRoutingMetricsStore creates a store rooted at dir.
func NewRoutingMetricsStore(dir string) *RoutingMetricsStore {
	return &RoutingMetricsStore{Dir: dir}
}

func (s *RoutingMetricsStore) outcomeFile() string {
	return filepath.Join(s.Dir, routingOutcomeFileName)
}

func (s *RoutingMetricsStore) burnFile() string {
	return filepath.Join(s.Dir, burnSummaryFileName)
}

// AppendOutcome writes one routing outcome record.
func (s *RoutingMetricsStore) AppendOutcome(outcome RoutingOutcome) error {
	return appendJSONLRecord(s.outcomeFile(), outcome)
}

// ReadOutcomes loads all recorded routing outcomes.
func (s *RoutingMetricsStore) ReadOutcomes() ([]RoutingOutcome, error) {
	return ReadAllJSONL[RoutingOutcome](s.outcomeFile())
}

// ReadBurnSummaries loads stored burn summaries.
func (s *RoutingMetricsStore) ReadBurnSummaries() ([]BurnSummary, error) {
	return ReadAllJSONL[BurnSummary](s.burnFile())
}

func appendJSONLRecord(path string, v any) error {
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		return err
	}
	data, err := json.Marshal(v)
	if err != nil {
		return err
	}
	f, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644)
	if err != nil {
		return err
	}
	defer f.Close()
	if _, err := f.Write(append(data, '\n')); err != nil {
		return err
	}
	return nil
}

func (r *Runner) recordRoutingOutcome(result *Result, elapsed time.Duration, opts RunArgs) {
	if r == nil || result == nil || r.Config.SessionLogDir == "" {
		return
	}

	harness, _ := r.registry.Get(result.Harness)
	canonicalTarget := result.Model
	if canonicalTarget == "" {
		canonicalTarget = opts.Model
	}
	if canonicalTarget == "" && harness.DefaultModel != "" {
		canonicalTarget = harness.DefaultModel
	}
	if canonicalTarget == "" {
		canonicalTarget = result.Harness
	}

	outcome := RoutingOutcome{
		Harness:         result.Harness,
		Surface:         harness.Surface,
		CanonicalTarget: canonicalTarget,
		Model:           result.Model,
		ObservedAt:      time.Now().UTC(),
		Success:         result.ExitCode == 0 && result.Error == "",
		LatencyMS:       int(elapsed.Milliseconds()),
		InputTokens:     result.InputTokens,
		OutputTokens:    result.OutputTokens,
		CostUSD:         result.CostUSD,
		NativeSessionID: result.AgentSessionID,
	}

	if opts.Correlation != nil {
		outcome.TraceID = opts.Correlation["trace_id"]
		outcome.SpanID = opts.Correlation["span_id"]
		if outcome.NativeSessionID == "" {
			outcome.NativeSessionID = opts.Correlation["native_session_id"]
		}
		if outcome.NativeLogRef == "" {
			outcome.NativeLogRef = opts.Correlation["native_log_ref"]
		}
	}

	_ = NewRoutingMetricsStore(r.Config.SessionLogDir).AppendOutcome(outcome)
}

package agent

import (
	"fmt"
	"os"
	"path/filepath"
	"time"

	"gopkg.in/yaml.v3"
)

// ModelCatalogYAML is the on-disk format for the model catalog.
// Stored at ~/.ddx/model-catalog.yaml.
// Drives tier→model assignments and pricing without requiring a rebuild.
type ModelCatalogYAML struct {
	Version   int                    `yaml:"version"`
	UpdatedAt time.Time              `yaml:"updated_at"`
	Tiers     map[string]TierDefYAML `yaml:"tiers"`  // tier name → surface→model
	Models    []ModelEntryYAML       `yaml:"models"` // per-model metadata and pricing
}

// TierDefYAML maps surfaces to concrete model strings for a tier.
type TierDefYAML struct {
	Description string            `yaml:"description"`
	Surfaces    map[string]string `yaml:"surfaces"` // surface → concrete model
}

// ModelEntryYAML holds metadata for one model.
type ModelEntryYAML struct {
	ID       string `yaml:"id"` // e.g. "claude-sonnet-4-6"
	Provider string `yaml:"provider"`
	Tier     string `yaml:"tier"`              // smart, standard, cheap
	Blocked  bool   `yaml:"blocked,omitempty"` // if true, routing never selects this model
	Notes    string `yaml:"notes,omitempty"`
}

// DefaultModelCatalogPath returns the default path for the model catalog YAML.
func DefaultModelCatalogPath() string {
	home, err := os.UserHomeDir()
	if err != nil || home == "" {
		return ""
	}
	return filepath.Join(home, ".ddx", "model-catalog.yaml")
}

// LoadModelCatalogYAML loads the model catalog from the given path.
// Returns nil (no error) if the file does not exist — callers fall back to built-in defaults.
func LoadModelCatalogYAML(path string) (*ModelCatalogYAML, error) {
	data, err := os.ReadFile(path)
	if os.IsNotExist(err) {
		return nil, nil
	}
	if err != nil {
		return nil, err
	}
	var cat ModelCatalogYAML
	if err := yaml.Unmarshal(data, &cat); err != nil {
		return nil, fmt.Errorf("parse model catalog: %w", err)
	}
	return &cat, nil
}

// ApplyModelCatalogYAML overlays the YAML catalog onto a Catalog, adding or
// replacing entries for each tier defined in the YAML.
func ApplyModelCatalogYAML(cat *Catalog, yml *ModelCatalogYAML) {
	if yml == nil || cat == nil {
		return
	}
	for tierName, tierDef := range yml.Tiers {
		entry := CatalogEntry{
			Ref:      tierName,
			Surfaces: make(map[string]string, len(tierDef.Surfaces)),
		}
		for surface, model := range tierDef.Surfaces {
			entry.Surfaces[surface] = model
		}
		cat.AddOrReplace(entry)
	}
	for _, m := range yml.Models {
		if m.Blocked {
			cat.AddBlockedModelID(m.ID)
		}
	}
}

// DefaultModelCatalogYAML returns the built-in seed catalog.
// Used when no ~/.ddx/model-catalog.yaml exists yet.
